// Вспомогательные скрипты


document.addEventListener("DOMContentLoaded", function () {
	// При клике на элемент переключаем, удаляем или добавляем класс для другого эелемента.
	// Параметры:
	// actionElement - класс элемета для клика,
	// targetElement - класс изменяемого элемента,
	// tagetClass - с каким классом выполняется действие, toggle по-умолчанию
	// targetAction - какое действие выполняем (toggle, remove, add), toggle по-умолчанию   
	const classToggle = (actionElement, targetElement, targetClass = "active", targetAction = "toggle") => {
		const actionElements = document.querySelectorAll(actionElement);
		const targetElements = document.querySelectorAll(targetElement);

		if (!actionElements.length) return; // Прекращаем выполнение, если нет элементов для клика

		actionElements.forEach((actionEl, index) => {
			actionEl.addEventListener("click", (e) => {
				e.preventDefault();

				// Получаем соответствующий целевой элемент по индексу или используем первый, если индекс выходит за пределы
				const targetEl = targetElements[index] || targetElements[0];

				switch (targetAction) {
					case "add":
						targetEl.classList.add(targetClass);
						break;
					case "remove":
						targetEl.classList.remove(targetClass);
						break;
					default:
						targetEl.classList.toggle(targetClass);
						break;
				}
			});
		});

		console.log("targetElements class edited!");
	};

	// Вызов функции
	// classToggle(".category-filters__toggle", ".category-filters");



	// По клику на любой элемент с указанным классом изменяем его класс. Поддерживается множество элементов
	// Параметры:
	// element - сам элемент, его класс
	// tagetClass = класс, который хотим добавить, удалить, переключить
	// tagetClassAction = действие с классом add, remove, toggle

	let elementToggle = function (
		element,
		tagetClass = "toggle",
		tagetClassAction = "toggle"
	) {
		if (document.querySelector(element)) {
			const elements = document.querySelectorAll(element);
			elements.forEach(function (elem, index) {
				elem.addEventListener("click", function (e) {
					e.preventDefault();

					switch (tagetClassAction) {
						case "add":
							this.classList.add(tagetClass);
							break;

						case "remove":
							this.classList.remove(tagetClass);
							break;

						default:
							this.classList.toggle(tagetClass);
							break;
					}
				});
			});
		}
	};

	
	// elementToggle("submenu-link", "submenu-link", "remove"); // для класса submenu-link делаем remove класса submenu-link

});
